	n := newTestPanel()
	history := []PlanDisplay{{Filename: "done-plan.md", Status: "done"}}
	instances := []*session.Instance{makeInst("worker", "done-plan.md", session.Running)}
	n.SetData(nil, instances, history, nil, nil)

