	// Solo instances: solo header + 2 instances
	require.Len(t, n.rows, 3)
	assert.Equal(t, navRowSoloHeader, n.rows[0].Kind)
	assert.Equal(t, navRowInstance, n.rows[1].Kind)
	assert.Equal(t, navRowInstance, n.rows[2].Kind)
