func TestString_SectionHeaders(t *testing.T) {
	n := newTestPanel()
	n.SetSize(60, 40)
	plans := []PlanDisplay{
		{Filename: "active-plan.md"},
		{Filename: "idle-plan.md"},
	}
	instances := []*session.Instance{
		makeInst("worker", "active-plan.md", session.Running),
	}
	statuses := map[string]TopicStatus{
