)

const (
	SidebarPlanPrefix        = "__plan__"
	SidebarTopicPrefix       = "__topic__"
	SidebarPlanHistoryToggle = "__plan_history_toggle__"
	SidebarImportClickUp     = "__import_clickup__"
)

type PlanDisplay struct {
