	// Go back to instA
	n.SelectInstance(instA)

	// CycleNextActive should find instB even though its plan is collapsed
	n.CycleNextActive()
	assert.Equal(t, instB, n.GetSelectedInstance(), "cycle should auto-expand collapsed plan")
}

