func TestNavigation_LeftCollapsesAndJumpsToParent(t *testing.T) {
	n := newTestPanel()
	plans := []PlanDisplay{{Filename: "p.md"}}
	instances := []*session.Instance{
		makeInst("inst", "p.md", session.Running),
