func TestCycleActive_ExpandsCollapsedPlan(t *testing.T) {
	n := newTestPanel()
	plans := []PlanDisplay{
		{Filename: "a.md"},
		{Filename: "b.md"},
	}
	instA := makeInst("a-worker", "a.md", session.Running)
	instB := makeInst("b-worker", "b.md", session.Running)
