func TestSortOrder_InstancesWithinPlan(t *testing.T) {
	n := newTestPanel()
	plans := []PlanDisplay{{Filename: "plan.md"}}
	instances := []*session.Instance{
		makeInst("paused", "plan.md", session.Paused),
